// При изменении тумблера "Стать пиром"
if (E.togglePeerHelp) {
    E.togglePeerHelp.addEventListener('change', function() {
        peerHelpEnabled = this.checked;
        localStorage.setItem('robinhood_peer_help', peerHelpEnabled);
        if (peerHelpEnabled) {
            if (myPeerId) {
                window.RobinHoodPeerHelp.start(myPeerId);
                rMsg('🤝 Помощь сети активирована', 3000);
            }
        } else {
            window.RobinHoodPeerHelp.stop();
            rMsg('🤝 Помощь сети отключена', 3000);
        }
    });
}

// После получения myPeerId от Понга
if (peerHelpEnabled && myPeerId) {
    window.RobinHoodPeerHelp.start(myPeerId);
}
